class Solution {
public:
    vector<int> pivotArray(vector<int>& nums, int pivot) {
        int less = 0;
        int equal = 0;
        int greater = nums.size() - 1;
        while (equal <= greater) {
            if (nums[equal] < pivot) {
                swap(nums[less++], nums[equal++]);
            } else if (nums[equal] > pivot) {
                swap(nums[equal], nums[greater--]);
            } else {
                equal++;
            }
        }
        return nums;
    }
};
```
